UPDATE public.projects p SET metadata_completeness = (
  ROUND(100.0 * (
    (CASE WHEN COALESCE(array_length(p.study_species,1),0)>0 THEN 1 ELSE 0 END) +
    (CASE WHEN COALESCE(array_length(p.keywords,1),0)>0 THEN 1 ELSE 0 END) +
    (CASE WHEN p.website IS NOT NULL AND p.website<>'' THEN 1 ELSE 0 END) +
    (CASE WHEN jsonb_typeof(p.metadata->'data_types_collected')='array' AND jsonb_array_length(p.metadata->'data_types_collected')>0 THEN 1 ELSE 0 END) +
    (CASE WHEN jsonb_typeof(p.metadata->'use_sensors')='array' AND jsonb_array_length(p.metadata->'use_sensors')>0 THEN 1 ELSE 0 END) +
    (CASE WHEN jsonb_typeof(p.metadata->'use_analysis_method')='array' AND jsonb_array_length(p.metadata->'use_analysis_method')>0 THEN 1 ELSE 0 END) +
    (CASE WHEN jsonb_typeof(p.metadata->'use_analysis_types')='array' AND jsonb_array_length(p.metadata->'use_analysis_types')>0 THEN 1 ELSE 0 END)
  ) / 7.0)::int
) WHERE grant_number IN ('R34DA059513','R34DA059506','R61MH135106','R34DA059716','R34DA059507','R34DA059718','R34DA061924','R34DA059723','R34DA059514','R61MH135109','R34DA059510','R61MH138713','R34DA061925','1U01DA063534','1R61MH138612','1U01DA063581','1U01DA063565');